const resp = $input.first().json;
const items = resp.data || [];
const cutoff = Date.now() - 4*3600*1000; // last 4h
const recent = items.filter(e => new Date(e.startedAt).getTime() >= cutoff);

const classifyError = (msg) => {
  if (!msg) return 'unknown';
  const m = msg.toLowerCase();
  if (m.includes('rate limit') || m.includes('429')) return 'rate_limit';
  if (m.includes('token') && m.includes('expir')) return 'token_expired';
  if (m.includes('timeout') || m.includes('etimedout')) return 'timeout';
  if (m.includes('econnrefused') || m.includes('connection refused')) return 'pg_down';
  if (m.includes('permission denied')) return 'pg_perms';
  if (m.includes('invalid input syntax')) return 'sql_error';
  if (m.includes('syntaxerror')) return 'js_syntax';
  return 'other';
};

const grouped = {};
const critical = [];
for (const e of recent) {
  const wid = e.workflowId;
  const wname = e.workflowName || wid;
  const t = classifyError(e.stoppedAt ? '' : '');
  if (!grouped[wname]) grouped[wname] = { count: 0, types: {} };
  grouped[wname].count++;
  grouped[wname].types[t] = (grouped[wname].types[t]||0) + 1;
  if (t === 'unknown' || t === 'other') {
    critical.push({wf: wname, exec: e.id, started: e.startedAt});
  }
}

const stat = {
  total_recent_failures: recent.length,
  workflows_affected: Object.keys(grouped).length,
  by_workflow: grouped,
  critical_count: critical.length,
  critical_first_5: critical.slice(0, 5),
  needs_cto_alert: critical.length >= 3 || recent.length >= 10,
  status: recent.length === 0 ? 'idle' :
          recent.length < 3   ? 'running' :
          critical.length >= 3 ? 'degraded' : 'running'
};
return [{ json: stat }];
